import React, { useState } from 'react';

const App = () => {
  const [message, setMessage] = useState('');
  const [typing, setTyping] = useState(false);

  const handleTyping = () => setTyping(true);
  const handleStopTyping = () => setTyping(false);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="flex items-center bg-[#B7D7CD] p-4 rounded-md">
        <div className="bg-[#C06C88] rounded-full p-2 text-white mr-4"></div>
        <input type="text" onChange={(e) => setMessage(e.target.value)} placeholder="Message" className="bg-transparent border-none outline-none text-white text-lg"/>
        <button className="bg-transparent border-none outline-none ml-4" onClick={handleTyping}>Typing...</button>
      </div>
      <div className="bg-[#B7D7CD] p-4 rounded-md mt-4" style={{display: typing ? 'block' : 'none'}}>
        <div className="bg-[#C06C88] p-2 rounded-full text-white"></div>
        <div className="text-sm text-[#411C56]">Typing...</div>
      </div>
    </div>
  );
};

export default App;
